// Pega dados dos nós anteriores
const openaiData = $('OpenAI Usage API').first().json;
const datas = $('Calcular datas').first().json;
const supabaseData = $('Calcular leads/handoffs').first().json;

// Tentar extrair custos da OpenAI
let openai_input = 0;
let openai_output = 0;
let openai_requests = 0;
let openai_custo = 0;

try {
  if (openaiData && openaiData.data) {
    for (const bucket of openaiData.data) {
      for (const result of (bucket.results || [])) {
        openai_input += result.input_tokens || 0;
        openai_output += result.output_tokens || 0;
        openai_requests += result.num_model_requests || 0;
      }
    }
    // Estimativa de custo (média ponderada dos modelos)
    // GPT-5: $2/1M input, $8/1M output
    // GPT-4o: $2.50/1M input, $10/1M output  
    // GPT-4o-mini: $0.15/1M input, $0.60/1M output
    // Whisper: ~$0.006/min
    openai_custo = (openai_input / 1000000 * 2.0) + (openai_output / 1000000 * 8.0);
  }
} catch(e) {
  // Se falhou, estima baseado no número de leads
  const leads = supabaseData?.leads || 0;
  openai_custo = leads * 0.03; // ~$0.03 por lead (estimativa)
}

// Estimativa Anthropic baseada em volume
// Claude Sonnet 4: $3/1M input, $15/1M output
// Média: ~2000 input + ~500 output tokens por interação
// ~5 interações por lead
const leads = supabaseData?.leads || 0;
const anthropic_input_est = leads * 5 * 2000;
const anthropic_output_est = leads * 5 * 500;
const anthropic_custo = (anthropic_input_est / 1000000 * 3.0) + (anthropic_output_est / 1000000 * 15.0);

// Google Gemini (estimativa)
const google_custo = leads * 0.002; // muito barato

// Totais
const custo_total_usd = openai_custo + anthropic_custo + google_custo;
const cotacao = 5.80;
const custo_total_brl = custo_total_usd * cotacao;
const handoffs = supabaseData?.handoffs || 0;

const threshold = 50.00; // USD por semana

return [{
  json: {
    periodo_inicio: datas.periodo_inicio,
    periodo_fim: datas.periodo_fim,
    openai_tokens_input: openai_input,
    openai_tokens_output: openai_output,
    openai_custo_usd: Math.round(openai_custo * 10000) / 10000,
    openai_requests: openai_requests,
    anthropic_tokens_input: anthropic_input_est,
    anthropic_tokens_output: anthropic_output_est,
    anthropic_custo_usd: Math.round(anthropic_custo * 10000) / 10000,
    google_custo_usd: Math.round(google_custo * 10000) / 10000,
    custo_total_usd: Math.round(custo_total_usd * 100) / 100,
    custo_total_brl: Math.round(custo_total_brl * 100) / 100,
    cotacao_usd_brl: cotacao,
    leads_no_periodo: leads,
    handoffs_no_periodo: handoffs,
    custo_por_lead: leads > 0 ? Math.round((custo_total_brl / leads) * 100) / 100 : 0,
    custo_por_handoff: handoffs > 0 ? Math.round((custo_total_brl / handoffs) * 100) / 100 : 0,
    acima_do_threshold: custo_total_usd > threshold,
    threshold_usd: threshold
  }
}];

